      900 -> ERROR_CODE_WASM_LOAD_FAILED
      901 -> ERROR_CODE_WASM_NOT_LOADED
      902 -> ERROR_CODE_WASM_CALLBACK_ERROR
      903 -> ERROR_CODE_WASM_MEMORY_ERROR
      else -> null
    }
  }
}
